normalized_obligations.lean_statement:
∀ (w v : List Nat) (cap : Nat) (S : Finset Nat), w.length = v.length →
  (∀ i ∈ S, i < w.length) →
  let totalW := (S.sum (fun i => w.get ⟨i, by simpa using (Fin.isLt i (by simpa using ‹i < w.length›))⟩))
  let totalV := (S.sum (fun i => v.get ⟨i, by simpa using (Fin.isLt i (by simpa using ‹i < w.length›))⟩))
  totalW ≤ cap → True

∀ (w v : List Nat) (cap : Nat) (S : Finset Nat), w.length = v.length →
  (∀ i ∈ S, i < w.length) →
  let totalW := S.sum (fun i => w.get ⟨i, by simpa using (Fin.isLt i (by simpa using ‹i < w.length›))⟩)
  let totalV := S.sum (fun i => v.get ⟨i, by simpa using (Fin.isLt i (by simpa using ‹i < w.length›))⟩)
  totalW ≤ cap →
  totalV ≤ knap w v cap

∀ (w v : List Nat) (cap : Nat), w.length = v.length →
  ∃ (S : Finset Nat),
    (∀ i ∈ S, i < w.length) ∧
    let totalW := S.sum (fun i => w.get ⟨i, by simpa using (Fin.isLt i (by simpa using ‹i < w.length›))⟩)
    let totalV := S.sum (fun i => v.get ⟨i, by simpa using (Fin.isLt i (by simpa using ‹i < w.length›))⟩)
    totalW ≤ cap ∧ knap w v cap = totalV

∀ (w v : List Nat) (cap : Nat), w.length = v.length →
  knap w v cap = 
    (Finset.univ.filter (fun i => i < w.length)).sup (fun S =>
      let totalW := S.sum (fun i => w.get ⟨i, by simpa using (Fin.isLt i (by simpa using ‹i < w.length›))⟩)
      let totalV := S.sum (fun i => v.get ⟨i, by simpa using (Fin.isLt i (by simpa using ‹i < w.length›))⟩)
      if totalW ≤ cap then totalV else 0)
